import axios from 'axios';

const API_BASE_URL = process.env.VUE_APP_API_BASE_URL || 'http://localhost:3000';

// Create axios instance with default config
const api = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

// Get all notes for a user
export const getUserNotes = async (userId, retryCount = 0) => {
  try {
    const response = await api.get(`/api/notes/user/${userId}`);
    return response.data.data;
  } catch (error) {
    console.error('Error fetching user notes:', error);

    // Handle rate limiting with exponential backoff
    if (error.response?.status === 429 && retryCount < 3) {
      const delay = Math.pow(2, retryCount) * 1000; // 1s, 2s, 4s
      console.log(`Rate limited. Retrying getUserNotes in ${delay}ms...`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return getUserNotes(userId, retryCount + 1);
    }

    throw error;
  }
};

// Get a specific note by ID
export const getNoteById = async (noteId) => {
  try {
    const response = await api.get(`/api/notes/${noteId}`);
    return response.data.data;
  } catch (error) {
    console.error('Error fetching note:', error);
    throw error;
  }
};

// Create a new note
export const createNote = async (noteData) => {
  try {
    const response = await api.post('/api/notes', noteData);
    return response.data.data;
  } catch (error) {
    console.error('Error creating note:', error);
    throw error;
  }
};

// Update a note
export const updateNote = async (noteId, noteData) => {
  try {
    const response = await api.put(`/api/notes/${noteId}`, noteData);
    return response.data.data;
  } catch (error) {
    console.error('Error updating note:', error);
    throw error;
  }
};

// Delete a note
export const deleteNote = async (noteId) => {
  try {
    const response = await api.delete(`/api/notes/${noteId}`);
    return response.data;
  } catch (error) {
    console.error('Error deleting note:', error);
    throw error;
  }
};

// Toggle favorite status
export const toggleNoteFavorite = async (noteId) => {
  try {
    const response = await api.patch(`/api/notes/${noteId}/favorite`);
    return response.data.data;
  } catch (error) {
    console.error('Error toggling note favorite:', error);
    throw error;
  }
};

export default {
  getUserNotes,
  getNoteById,
  createNote,
  updateNote,
  deleteNote,
  toggleNoteFavorite,
};
